import bisect

def k_element_sorted(arr, k):
    # O(N) - > Sort using above and then find k-th elm
    # O(K) -> Find inflection point using bisect left, then two pointer traversal to both directions, 
    # O(LogN) -> Find inflection point. Then binary search of partition.
    N = len(arr)
    idx_0 = bisect.bisect_left(arr, 0)

    if idx_0 == N:
        # Case where all numbers are negative
        return arr[-k]
    if idx_0 == 0:
        # Case where all numbers are non-negative; k is 1-indexed
        return arr[k - 1]
    if arr[idx_0] == 0:
        # 0 in arr and hence the start point.
        pass
    elif abs(arr[idx_0]) < abs(arr[idx_0-1]):
        # Smallest positive is smaller in magnitude than largest negative, hence start point is smallest postive
        pass
    else:
        # Smallest positive is greater in magnitude than largest negative, hence start point is largest negative
        idx_0 -= 1

    low, high = 0, k
    while low <= high:
        mid  = low + (high-low)//2
        left = idx_0 - mid + 1
        right = idx_0 + (k-mid)

        if left-1 >= 0 and abs(arr[left-1]) <= abs(arr[right]):
            low = mid + 1
        elif right+1 < N and abs(arr[right+1]) < abs(arr[left]):
            high = mid -1
        else:
            if abs(arr[left]) > abs(arr[right]):
                return arr[left]
            else:
                return arr[right]

